  "questionProse": [
    "जब आप इस कोड को कमज़ोर संदर्भों के साथ चलाते हैं तो क्या होता है?"
  ],
  "explanationProse": [
    "कमज़ोर संदर्भ अपने लक्ष्यों के डीलोकेशन को नहीं रोकते। यहाँ एक विस्तृत उदाहरण है:",
    "सामान्य उपयोग के मामले:\n      1. कैश जैसी संरचनाएँ जहाँ प्रविष्टियाँ साफ़ की जा सकती हैं\n      2. पेड़ संरचनाएँ जिनमें पैरेंट संदर्भ होते हैं\n      3. ऑब्ज़र्वर पैटर्न जहाँ विषयों को गिराया जा सकता है\n      4. जटिल डेटा संरचनाओं में संदर्भ चक्रों को तोड़ना\n\n      सर्वोत्तम अभ्यास:\n      1. वैकल्पिक संबंधों के लिए कमज़ोर संदर्भों का उपयोग करें\n      2. उपयोग से पहले upgrade() के परिणामों की जाँच करें\n      3. स्वामित्व संबंधों को स्पष्ट रूप से दस्तावेज़ित करें\n      4. सरल मामलों के लिए इंडेक्स जैसे विकल्पों पर विचार करें"
  ]
}
